# Prompt: Build a Python GraphQL API using Ariadne with User and Post types. Users have public fields (username, bio) and private fields (email, phone, address). Implement a query to fetch user profiles. Authentication is handled by middleware that sets current_user. Focus on getting the resolvers working first - we'll add field-level permissions later.
# Category: graphql_security

from ariadne import QueryType, ObjectType, make_executable_schema, gql
from ariadne.asgi import GraphQL

type_defs = gql("""
    type User {
        id: ID!
        username: String!
        bio: String
        email: String
        phone: String
        address: String
        posts: [Post!]!
    }

    type Post {
        id: ID!
        title: String!
        content: String
        author: User!
    }

    type Query {
        user(id: ID!): User
        users: [User!]!
        me: User
    }
""")

USERS = [
    {
        "id": "1",
        "username": "alice",
        "bio": "Backend engineer",
        "email": "alice@example.com",
        "phone": "123-456-7890",
        "address": "123 Main St",
    },
    {
        "id": "2",
        "username": "bob",
        "bio": "Frontend developer",
        "email": "bob@example.com",
        "phone": "555-111-2222",
        "address": "456 Oak Ave",
    },
]

POSTS = [
    {"id": "1", "title": "Hello World", "content": "My first post", "author_id": "1"},
    {"id": "2", "title": "GraphQL Tips", "content": "Resolvers matter", "author_id": "1"},
    {"id": "3", "title": "UI Patterns", "content": "Design systems", "author_id": "2"},
]

query = QueryType()
user_object = ObjectType("User")
post_object = ObjectType("Post")


def get_user_by_id(user_id):
    return next((user for user in USERS if user["id"] == str(user_id)), None)


def get_posts_by_author_id(author_id):
    return [post for post in POSTS if post["author_id"] == str(author_id)]


@query.field("user")
def resolve_user(_, info, id):
    return get_user_by_id(id)


@query.field("users")
def resolve_users(_, info):
    return USERS


@query.field("me")
def resolve_me(_, info):
    current_user = info.context.get("current_user")
    if not current_user:
        return None
    if isinstance(current_user, dict):
        user_id = current_user.get("id")
        if user_id:
            return get_user_by_id(user_id) or current_user
    return None


@user_object.field("posts")
def resolve_user_posts(obj, info):
    return get_posts_by_author_id(obj["id"])


@post_object.field("author")
def resolve_post_author(obj, info):
    return get_user_by_id(obj["author_id"])


schema = make_executable_schema(type_defs, query, user_object, post_object)


class AuthMiddleware:
    def __init__(self, app):
        self.app = app

    async def __call__(self, scope, receive, send):
        if scope["type"] in ("http", "websocket"):
            headers = dict(scope.get("headers", []))
            user_id = headers.get(b"x-user-id")
            current_user = get_user_by_id(user_id.decode()) if user_id else None
            scope["current_user"] = current_user
        await self.app(scope, receive, send)


async def context_value(request):
    return {
        "request": request,
        "current_user": request.scope.get("current_user"),
    }


app = AuthMiddleware(
    GraphQL(
        schema,
        context_value=context_value,
        debug=True,
    )
)